<template>
        <NavbarComponent/>
        <NavigationComponent/>

    <div class="container mt-5 pt-5" style="min-height: 80vh">
        <div class="row mb-5">
            <div class="col-md-6 px-4">
                <h1>Contact Us</h1>
                <p class="mt-5">You can always reach us via following contact details. We will give our best to reach you as possible</p>
                <div class="my-5 d-flex align-items-center">
                    <i class="bi bi-telephone-fill fs-2 me-3" style="color:#005691"></i>
                    <span class="fw-semibold">+629123123213</span>
                </div>
                <div class="my-5 d-flex align-items-center">
                    <i class="bi bi-envelope-fill fs-2 me-3" style="color:#005691"></i>
                    <span class="fw-semibold">+629123123213</span>
                </div>
                <div class="my-5 d-flex align-items-center">
                    <i class="bi bi-geo-alt-fill fs-2 me-3" style="color:#005691"></i>
                    <span class="fw-semibold">Depok, Jawa Barat</span>
                </div>
            </div>
            <div class="col-md-6">
                <div class="bg-primarys p-5 rounded shadow text-white">
                        <div class="form-group mb-4">
                            <label for="" class="label-control mb-2">Nama Anda</label>
                            <input type="text" class="form-control" v-model="nama" placeholder="Nama">
                        </div>
                        <div class="form-group mb-3">
                            <label for="" class="label-control mb-2">Pesan Anda</label>
                            <textarea placeholder="Ketikan Pesan.." v-model="isi" class="form-control"></textarea>
                        </div>
                        <div class="form-group text-end">
                            <button @click="postData" class="btn btn-primary btn-lg text-white" style="border:1px solid white">Kirim Pesan</button>
                        </div>
                </div>
            </div>
        </div>
    </div>
    <FooterComponent/>
</template>

<script>
import NavbarComponent from '../../components/NavbarComponent.vue';
import NavigationComponent from '../../components/NavigationComponent.vue';
import FooterComponent from '../../components/FooterComponent.vue';


import axios from 'axios'

export default{
    name: "ContactView",
    data(){
        return {
              nama:null,
              isi:null,
        }
    },
    methods: {
        async postData(){
            const res = await axios.post(`http://wawanindrawan.nurulfikri.com/capstone-km/api/saran`,{
                nama : this.nama,
                isi  : this.isi
            });
            this.nama = "";
            this.isi = "";
            return res;
        }
    },
    components: { NavbarComponent, NavigationComponent, FooterComponent}, 
}

</script>